const items = $input.all();
let transcriptText = '';
let videoTitle = 'YouTube Video';

for (const item of items) {
  const data = item.json;

  // pintostudio actor returns array of {text, start, duration}
  if (Array.isArray(data) ) {
    transcriptText += data.map(d => d.text || d).filter(Boolean).join(' ') + ' ';
  }
  if (typeof data.transcript === 'string') {
    transcriptText += data.transcript + ' ';
  } else if (Array.isArray(data.transcript)) {
    transcriptText += data.transcript.map(t => t.text || t).filter(Boolean).join(' ') + ' ';
  }
  if (Array.isArray(data.captions)) {
    transcriptText += data.captions.map(c => c.text || c).filter(Boolean).join(' ') + ' ';
  }
  if (typeof data.text === 'string') {
    transcriptText += data.text + ' ';
  }
  if (data.title) videoTitle = data.title;
  if (data.videoTitle) videoTitle = data.videoTitle;
}

// Deep scan: pull all 'text' string values recursively
if (!transcriptText.trim()) {
  function extractText(obj) {
    if (!obj || typeof obj !== 'object') return '';
    let out = '';
    for (const key of Object.keys(obj)) {
      if (key === 'text' && typeof obj[key] === 'string') out += obj[key] + ' ';
      else out += extractText(obj[key]);
    }
    return out;
  }
  transcriptText = items.map(i => extractText(i.json)).join(' ');
}

if (!transcriptText.trim()) {
  throw new Error('Could not extract transcript. Check Apify actor response in previous node.');
}

const trimmed = transcriptText.trim().substring(0, 6000);

return [{
  json: {
    transcript: trimmed,
    videoTitle,
    youtubeUrl: $('① Form — Input YouTube URL').item.json['YouTube Video URL'],
    charCount: trimmed.length
  }
}];

