const response = $input.first().json;

let mermaidCode = '';
try {
  mermaidCode = response.candidates[0].content.parts[0].text;
} catch (e) {
  throw new Error('Gemini response parse failed: ' + JSON.stringify(response).substring(0, 400));
}

// Strip any fences Gemini might add
mermaidCode = mermaidCode
  .replace(/```mermaid/gi, '')
  .replace(/```/g, '')
  .trim();

// Ensure starts with mindmap
if (!mermaidCode.toLowerCase().startsWith('mindmap')) {
  mermaidCode = 'mindmap\n' + mermaidCode;
}

console.log('Mermaid output:', mermaidCode);

// Build mermaid.ink URLs
const base64 = Buffer.from(mermaidCode, 'utf-8').toString('base64')
  .replace(/\+/g, '-').replace(/\//g, '_').replace(/=/g, '');

const imageUrl = `https://mermaid.ink/img/${base64}?type=png&bgColor=f8f9ff`;
const svgUrl   = `https://mermaid.ink/svg/${base64}`;

// Mermaid Live editor
const editorState = Buffer.from(JSON.stringify({ code: mermaidCode, mermaid: '{"theme":"default"}', autoSync: true })).toString('base64').replace(/\+/g, '-').replace(/\//g, '_');
const editorUrl = `https://mermaid.live/edit#base64:${editorState}`;

const videoTitle = $('③ Code — Extract Transcript').first().json.videoTitle;
const youtubeUrl = $('③ Code — Extract Transcript').first().json.youtubeUrl;

return [{ json: { mermaidCode, imageUrl, svgUrl, editorUrl, videoTitle, youtubeUrl } }];
